35      float t = u_time * 0.8 + u_drag_float * 2.0;
36      vec3 center = u_drag_vec3 * 1.5;
37      // simple automatic orbit animation around Y axis
38      center.x += sin(u_time * 1.2) * 0.6;
39      center.z += cos(u_time * 1.2) * 0.6;
40      float r = 0.8 + u_drag_vec4.x * 0.6 + params.a.x * 0.2;
41      r += sin(u_floats[0] * 6.28318) * 0.05;
42      return sdSphere(p - center, r);
