45  vec3 calcNormal(vec3 p) {
46      const float h = 0.001;
47      return normalize(vec3(
48          map(p + vec3(h,0,0)) - map(p - vec3(h,0,0)),
49          map(p + vec3(0,h,0)) - map(p - vec3(0,h,0)),
50          map(p + vec3(0,0,h)) - map(p - vec3(0,0,h))
51      ));
