59      vec2 p = uv * 2.0 - 1.0;
60      float radius = length(p) + 0.02 * sin(u_time * 2.0 + u_drag_vec2.y * 6.28);
61      float angle  = atan(p.y, p.x);
62  
63      // concentric rings
64      float ring = abs(fract(radius * 6.0 + sin(u_time) * 0.5) - 0.5) * 2.0;
65      float mask = smoothstep(0.08, 0.0, ring);
66  
